export const QuotePDF = ({ quote }: { quote: Quote }) => {
  const challenges = [
    {
      title: "Renovación manual",
      desc: "130 socios contactados uno por uno cada año",
    },
    {
      title: "Portal abandonado",
      desc: "Los socios pierden sus números de membresía",
    },
    {
      title: "Eventos desconectados",
      desc: "Proveedores externos para cada evento",
    },
    {
      title: "Difícil coordinación",
      desc: "Invitaciones por correo, WhatsApp y llamadas",
    },
    {
      title: "Baja respuesta de datos",
      desc: "Fondos no confían en el manejo de información",
    },
    {
      title: "Sitio desactualizado",
      desc: "No refleja el nivel de AMEXCAP",
    },
  ];

  const phases = [
    {
      number: "1",
      title: "Cimientos de la plataforma",
      duration: "2-3 meses",
      investment: 350000,
      description:
        "Backend completo, panel de administración, panel de socios, automatización de renovaciones, sistema de documentos seguro y notificaciones multicanal.",
    },
    {
      number: "2",
      title: "Reemplazo del sitio web y migración",
      duration: "0.5-1 mes",
      investment: 200000,
      description:
        "Nuevo sitio público conectado al ecosistema, diseño moderno y responsivo, login de socios integrado, optimización SEO.",
    },
    {
      number: "3",
      title: "Sistema de eventos",
      duration: "0.5-1 mes",
      investment: 150000,
      description:
        "Gestión de eventos, venta de boletos, integración con wallet, biblioteca digital de publicaciones, notificaciones automáticas.",
    },
  ];

  const steps = [
    "Reunión de revisión de propuesta y resolución de dudas",
    "Sprint de descubrimiento para detallar requerimientos",
    "Propuesta económica final de la Fase 1",
    "Kickoff y arranque de proyecto",
  ];

  return (
    <Document>
      <Page size="A4" style={styles.page}>
        {/* Header */}
        <View style={styles.header}>
          <Text style={styles.headerTitle}>{quote.title}</Text>
          <Text style={styles.headerSubtitle}>
            Para {quote.clientCompany || quote.clientName}
          </Text>
          <Text style={styles.headerMeta}>
            Propuesta preparada por PRAGMA • Fecha:{" "}
            {new Date().toLocaleDateString("es-MX")}
          </Text>
        </View>

        {/* Executive Summary */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Resumen Ejecutivo</Text>
          <Text style={styles.paragraph}>
            AMEXCAP requiere una plataforma integral que centralice la gestión
            de membresías, comunicaciones, eventos y presencia web. La solución
            se entrega en tres fases secuenciales para que reciba funcionalidad
            útil desde el primer mes y distribuya la inversión en el tiempo.
          </Text>
          <View
            style={{
              flexDirection: "row",
              justifyContent: "space-between",
              marginTop: 10,
            }}
          >
            <View style={{ flex: 1, marginRight: 12 }}>
              <Text style={{ fontSize: 10, fontWeight: "bold", color: "#00f0ff" }}>
                3-5 meses
              </Text>
              <Text style={{ fontSize: 9, color: "#666666" }}>
                Duración total
              </Text>
            </View>
            <View style={{ flex: 1, marginRight: 12 }}>
              <Text style={{ fontSize: 10, fontWeight: "bold", color: "#00f0ff" }}>
                $700,000 MXN
              </Text>
              <Text style={{ fontSize: 9, color: "#666666" }}>
                Inversión total
              </Text>
            </View>
            <View style={{ flex: 1 }}>
              <Text style={{ fontSize: 10, fontWeight: "bold", color: "#00f0ff" }}>
                3 fases
              </Text>
              <Text style={{ fontSize: 9, color: "#666666" }}>
                Entrega independiente
              </Text>
            </View>
          </View>
        </View>

        {/* Current Situation */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Retos Operativos Actuales</Text>
          {challenges.map((challenge, idx) => (
            <View key={idx} style={styles.challengeContainer}>
              <Text style={styles.challengeTitle}>{challenge.title}</Text>
              <Text style={styles.challengeDesc}>{challenge.desc}</Text>
            </View>
          ))}
        </View>

        {/* Solution */}
        <View style={[styles.highlightBox, { marginBottom: 20 }]}>
          <Text style={styles.sectionTitle}>La Solución: Una Plataforma Integral</Text>
          <Text style={styles.paragraph}>
            PRAGMA propone unificar todos estos sistemas en una sola plataforma
            que funcione como el sistema nervioso central de AMEXCAP. Una
            identidad de socio que conecte renovaciones, pagos, eventos,
            publicaciones, datos y comunicaciones.
          </Text>
        </View>

        {/* Phases */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Hoja de Ruta por Fases</Text>
          {phases.map((phase, idx) => (
            <View key={idx} style={styles.phaseContainer}>
              <View style={styles.phaseHeader}>
                <Text style={styles.phaseNumber}>{phase.number}</Text>
                <Text style={styles.phaseTitle}>{phase.title}</Text>
              </View>
              <View style={styles.phaseDetails}>
                <Text>⏱ {phase.duration}</Text>
                <Text style={{ color: "#00f0ff", fontWeight: "bold" }}>
                  ${phase.investment.toLocaleString("es-MX")} MXN
                </Text>
              </View>
              <Text style={styles.phaseDesc}>{phase.description}</Text>
            </View>
          ))}
        </View>
      </Page>

      {/* Page 2 */}
      <Page size="A4" style={styles.page}>
        {/* Investment Table */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Cronograma e Inversión</Text>
          <View style={styles.table}>
            <View style={[styles.tableRow, styles.tableHeader]}>
              <Text style={[styles.tableCell, styles.tableCellPhase]}>
                Fase
              </Text>
              <Text style={[styles.tableCell, styles.tableCellDuration]}>
                Duración
              </Text>
              <Text style={[styles.tableCell, styles.tableCellAmount]}>
                Inversión
              </Text>
            </View>
            {phases.map((phase, idx) => (
              <View
                key={idx}
                style={[
                  styles.tableRow,
                  idx === phases.length - 1 && styles.tableRowLast,
                ]}
              >
                <Text style={[styles.tableCell, styles.tableCellPhase]}>
                  {phase.title}
                </Text>
                <Text style={[styles.tableCell, styles.tableCellDuration]}>
                  {phase.duration}
                </Text>
                <Text style={[styles.tableCell, styles.tableCellAmount]}>
                  ${phase.investment.toLocaleString("es-MX")} MXN
                </Text>
              </View>
            ))}
            <View style={[styles.tableRow, { backgroundColor: "#f0f9ff" }]}>
              <Text
                style={[
                  styles.tableCell,
                  styles.tableCellPhase,
                  { fontWeight: "bold", color: "#00f0ff" },
                ]}
              >
                Total
              </Text>
              <Text
                style={[
                  styles.tableCell,
                  styles.tableCellDuration,
                  { fontWeight: "bold", color: "#00f0ff" },
                ]}
              >
                3-5 meses
              </Text>
              <Text
                style={[
                  styles.tableCell,
                  styles.tableCellAmount,
                  { fontWeight: "bold", color: "#00f0ff" },
                ]}
              >
                $700,000 MXN
              </Text>
            </View>
          </View>
          <Text
            style={{
              fontSize: 9,
              color: "#666666",
              fontStyle: "italic",
              marginTop: 8,
            }}
          >
            Cada fase entrega valor de forma independiente y puede aprobarse
            por separado.
          </Text>
        </View>

        {/* Next Steps */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Siguientes Pasos</Text>
          <View style={styles.stepsContainer}>
            {steps.map((step, idx) => (
              <View key={idx} style={styles.step}>
                <Text style={styles.stepNumber}>{idx + 1}</Text>
                <Text style={styles.stepText}>{step}</Text>
              </View>
            ))}
          </View>
        </View>

        {/* Footer */}
        <View style={styles.footer}>
          <Text>Propuesta preparada por PRAGMA</Text>
          <Text>Santiago Coronado • santiago.coronado94@gmail.com</Text>
          <Text>
            Válida hasta {quote.validUntil || "2026-05-30"}
          </Text>
        </View>
      </Page>
    </Document>
  );
};

